def range_step(start, stop, step):
    """
    Returns a list of integers from start up to but not including stop,
    advancing by step.

    Edge case handled: When step is zero or negative, an empty list is returned.
    """
    if step <= 0:
        return []
    elif start >= stop:
        return []
    else:
        return list(range(start, stop, step))
